import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  FaUser, 
  FaUserMd, 
  FaPills, 
  FaEye, 
  FaEyeSlash, 
  FaSpinner, 
  FaHeartbeat,
  FaLock,
  FaArrowLeft
} from 'react-icons/fa';

const Login = ({ onLogin }) => {
  const { t } = useTranslation();
  const [selectedRole, setSelectedRole] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [step, setStep] = useState('role'); // role, credentials
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  const roles = [
    {
      id: 'patient',
      name: 'Patient',
      icon: FaUser,
      gradient: 'from-blue-500 to-cyan-500',
      bgColor: 'bg-blue-50',
      borderColor: 'border-blue-200',
      textColor: 'text-blue-700',
      sampleUsername: 'p001'
    },
    {
      id: 'doctor',
      name: 'Doctor',
      icon: FaUserMd,
      gradient: 'from-emerald-500 to-teal-500',
      bgColor: 'bg-emerald-50',
      borderColor: 'border-emerald-200',
      textColor: 'text-emerald-700',
      sampleUsername: 'd001'
    },
    {
      id: 'pharmacist',
      name: 'Pharmacist',
      icon: FaPills,
      gradient: 'from-purple-500 to-violet-500',
      bgColor: 'bg-purple-50',
      borderColor: 'border-purple-200',
      textColor: 'text-purple-700',
      sampleUsername: 'pm001'
    }
  ];

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setStep('credentials');
    setError('');
    setUsername('');
    setPassword('');
  };

  const handleLogin = async () => {
    if (!username || !password) {
      setError('Please enter both username and password');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      console.log('🔐 Attempting login with:', { username, role: selectedRole });
      
      const payload = {
        username: username,
        password: password
      };
      
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload)
      });
      
      console.log('📡 Response status:', response.status);
      
      let data = {};
      try {
        data = await response.json();
      } catch (e) {
        console.error('Failed to parse JSON response');
      }
      console.log('📊 Response data:', data);
      
      if (response.ok) {
        const token = data.token || data.access_token;
        const user = data.user || {
          id: data.id || data.user_id,
          role: data.role || data.user_type,
          username: data.username || username,
        };
        
        if (!token) {
          throw new Error('Missing token in response');
        }
        
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(user));
        
        console.log('✅ Login successful, redirecting...');
        
        onLogin({
          ...user,
          token
        });
      } else {
        console.error('❌ Login failed:', data);
        const serverMsg = data?.message || data?.error || 'Login failed';
        setError(serverMsg);
      }
    } catch (err) {
      console.error('🚨 Login error:', err);
      if (err.name === 'TypeError' && err.message.includes('fetch')) {
        setError('Unable to connect to server. Please ensure the backend is running on http://localhost:5000');
      } else {
        setError('Network error. Please check your connection and try again.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const getCurrentRole = () => {
    return roles.find(role => role.id === selectedRole);
  };

  const handleBack = () => {
    setStep('role');
    setSelectedRole('');
    setError('');
    setUsername('');
    setPassword('');
  };

  const getPasswordForRole = (role) => {
    switch(role) {
      case 'patient': return 'patient123';
      case 'doctor': return 'doctor123';
      case 'pharmacist': return 'pharmacy123';
      default: return '';
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 flex flex-col">
      {/* Modern Header */}
      <div className="pt-8 pb-4 text-center">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl mb-4 shadow-lg">
          <FaHeartbeat className="text-white text-2xl" />
        </div>
        <h1 className="text-3xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
          Helio
        </h1>
        <p className="text-gray-600 text-sm mt-1">Healthcare Platform 2025</p>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex items-center justify-center px-6 py-8">
        <div className="w-full max-w-md">
          {/* Role Selection */}
          {step === 'role' && (
            <div className="space-y-8">
              {/* Title */}
              <div className="text-center mb-8">
                <h2 className="text-2xl font-bold text-gray-800 mb-2">Choose Your Role</h2>
                <p className="text-gray-600">Select how you'd like to access Helio</p>
              </div>

              {/* Role Buttons */}
              <div className="space-y-4">
                {roles.map((role) => {
                  const IconComponent = role.icon;
                  return (
                    <button
                      key={role.id}
                      onClick={() => handleRoleSelect(role.id)}
                      className={`w-full p-6 ${role.bgColor} ${role.borderColor} border-2 rounded-2xl hover:shadow-lg transition-all duration-300 transform hover:scale-[1.02] group`}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 bg-gradient-to-r ${role.gradient} rounded-xl flex items-center justify-center shadow-md group-hover:shadow-lg transition-shadow duration-300`}>
                          <IconComponent className="text-white text-xl" />
                        </div>
                        <div className="text-left">
                          <h3 className={`font-bold text-lg ${role.textColor}`}>{role.name}</h3>
                          <p className="text-gray-600 text-sm">Secure access portal</p>
                        </div>
                        <div className="ml-auto">
                          <svg className="w-5 h-5 text-gray-400 group-hover:text-gray-600 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                          </svg>
                        </div>
                      </div>
                    </button>
                  );
                })}
              </div>

              {/* Credentials Reference Card */}
              <div className="bg-white rounded-2xl p-6 shadow-lg border border-gray-100">
                <h3 className="text-lg font-bold text-gray-800 mb-4 text-center">Login Credentials</h3>
                
                {/* Usernames */}
                <div className="space-y-3 mb-6">
                  <div className="flex justify-between items-center p-3 bg-blue-50 rounded-xl">
                    <div className="flex items-center gap-3">
                      <FaUser className="text-blue-600 text-sm" />
                      <span className="font-semibold text-blue-700">Patients:</span>
                    </div>
                    <span className="text-gray-700 font-mono text-sm">p001, p002, p003</span>
                  </div>
                  
                  <div className="flex justify-between items-center p-3 bg-emerald-50 rounded-xl">
                    <div className="flex items-center gap-3">
                      <FaUserMd className="text-emerald-600 text-sm" />
                      <span className="font-semibold text-emerald-700">Doctors:</span>
                    </div>
                    <span className="text-gray-700 font-mono text-sm">d001, d002, d003</span>
                  </div>
                  
                  <div className="flex justify-between items-center p-3 bg-purple-50 rounded-xl">
                    <div className="flex items-center gap-3">
                      <FaPills className="text-purple-600 text-sm" />
                      <span className="font-semibold text-purple-700">Pharmacists:</span>
                    </div>
                    <span className="text-gray-700 font-mono text-sm">pm001, pm002, pm003</span>
                  </div>
                </div>

                {/* Default Passwords */}
                <div className="border-t border-gray-100 pt-4">
                  <div className="flex items-center justify-center gap-2 mb-4">
                    <FaLock className="text-gray-600 text-sm" />
                    <span className="font-bold text-gray-700">Default Passwords</span>
                  </div>
                  
                  <div className="grid grid-cols-1 gap-2 text-sm">
                    <div className="flex justify-between items-center p-2 bg-gray-50 rounded-lg">
                      <span className="text-gray-600">Patient:</span>
                      <span className="font-bold text-blue-600 font-mono">patient123</span>
                    </div>
                    <div className="flex justify-between items-center p-2 bg-gray-50 rounded-lg">
                      <span className="text-gray-600">Doctor:</span>
                      <span className="font-bold text-emerald-600 font-mono">doctor123</span>
                    </div>
                    <div className="flex justify-between items-center p-2 bg-gray-50 rounded-lg">
                      <span className="text-gray-600">Pharmacist:</span>
                      <span className="font-bold text-purple-600 font-mono">pharmacy123</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Login Form */}
          {step === 'credentials' && (
            <div className="space-y-6">
              {/* Back to role selection */}
              <button
                onClick={handleBack}
                className="flex items-center gap-2 text-gray-600 hover:text-gray-800 transition-colors"
              >
                <FaArrowLeft className="text-sm" />
                <span>Back to role selection</span>
              </button>

              {/* Role Header */}
              <div className="text-center">
                <div className={`w-16 h-16 bg-gradient-to-r ${getCurrentRole()?.gradient} rounded-2xl mx-auto mb-4 flex items-center justify-center shadow-lg`}>
                  {React.createElement(getCurrentRole()?.icon, { className: "text-white text-2xl" })}
                </div>
                <h2 className="text-2xl font-bold text-gray-800 mb-1">{getCurrentRole()?.name} Login</h2>
                <p className="text-gray-600">Enter your credentials to continue</p>
              </div>

              {/* Error Message */}
              {error && (
                <div className="p-4 bg-red-50 border border-red-200 rounded-xl">
                  <p className="text-red-700 text-sm">{error}</p>
                </div>
              )}

              {/* Login Form */}
              <div className="bg-white rounded-2xl p-6 shadow-lg border border-gray-100 space-y-6">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Username</label>
                  <input
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    placeholder={`e.g., ${getCurrentRole()?.sampleUsername}`}
                    className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200"
                    disabled={isLoading}
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Password</label>
                  <div className="relative">
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="Enter your password"
                      className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200 pr-12"
                      disabled={isLoading}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500 hover:text-gray-700 transition-colors"
                    >
                      {showPassword ? <FaEyeSlash size={18} /> : <FaEye size={18} />}
                    </button>
                  </div>
                </div>

                <button
                  onClick={handleLogin}
                  disabled={isLoading || !username || !password}
                  className={`w-full py-3 px-4 bg-gradient-to-r ${getCurrentRole()?.gradient} text-white rounded-xl font-semibold hover:shadow-lg disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-300 flex items-center justify-center gap-2`}
                >
                  {isLoading ? (
                    <>
                      <FaSpinner className="animate-spin" />
                      Signing in...
                    </>
                  ) : (
                    'Sign In'
                  )}
                </button>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Footer */}
      <div className="text-center py-6">
        <p className="text-gray-500 text-sm">🔒 Secure • 🚀 Fast • 🏥 Trusted Healthcare Platform</p>
      </div>
    </div>
  );
};

export default Login;
